# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

from strawberry import Schema, Field, Object
from strawberry.sqlalchemy import SQLAlchemyObjectType
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.orm import relationship

# Database setup
engine = create_engine('sqlite:///database.db')

class Product(SQLAlchemyObjectType):
    class Meta:
        model = engine.Table('products', autoload=True)

class Review(SQLAlchemyObjectType):
    class Meta:
        model = engine.Table('reviews', autoload=True)

class Seller(SQLAlchemyObjectType):
    class Meta:
        model = engine.Table('sellers', autoload=True)

class Category(SQLAlchemyObjectType):
    class Meta:
        model = engine.Table('categories', autoload=True)

class Image(SQLAlchemyObjectType):
    class Meta:
        model = engine.Table('images', autoload=True)

schema = Schema(
    query=Object(
        products=Field(
            Product.connection,
            arguments={'id': int},
            resolver=lambda root, info, id: Product.get(id),
        ),
        reviews=Field(
            Review.connection,
            arguments={'product_id': int},
            resolver=lambda root, info, product_id: Review.filter_by(product_id=product_id),
        ),
        sellers=Field(
            Seller.connection,
            arguments={'product_id': int},
            resolver=lambda root, info, product_id: Seller.filter_by(product_id=product_id),
        ),
        categories=Field(
            Category.connection,
            arguments={'product_id': int},
            resolver=lambda root, info, product_id: Category.filter_by(product_id=product_id),
        ),
        images=Field(
            Image.connection,
            arguments={'product_id': int},
            resolver=lambda root, info, product_id: Image.filter_by(product_id=product_id),
        ),
    )
)